bash -c "python3 -c \"
import json
with open('/tmp/orders.json') as f:
    data = json.load(f)
# Duplicate check - same user, same total, close timestamps
by_user = {}
for o in data:
    by_user.setdefault(o['user_id'], []).append(o)
for uid, orders in sorted(by_user.items()):
    by_total = {}
    for o in orders:
        by_total.setdefault(o['total_cents'], []).append(o)
    for total, group in by_total.items():
        if len(group) > 1:
            print(f'Potential duplicate: user={uid} total={total} orders={[(g[\"id\"], g[\"created_at\"], g[\"status\"]) for g in group]}')
\""

